def sha256_bytes(data: bytes) -> str:
    return hashlib.sha256(data).hexdigest()


def sha256_path(path: Path) -> str:
    return sha256_bytes(path.read_bytes())


def decode_payload(encoded: str) -> bytes:
    return zlib.decompress(base64.b85decode(encoded.encode("ascii")))


def target_site(explicit: str | None) -> Path:
    return Path(explicit) if explicit else DEFAULT_SITE


def validate_site(site: Path, version: str) -> bool:
    result = subprocess.run(
        [sys.executable, str(VALIDATE_SCRIPT), "--omlx-version", version, "--site-packages", str(site)],
        capture_output=True,
        text=True,
    )
    sys.stdout.write(result.stdout)
    sys.stderr.write(result.stderr)
    return result.returncode == 0


def apply_file(site: Path, rel: str, *, dry_run: bool, force: bool) -> tuple[bool, str]:
    meta = PAYLOADS[rel]
    target = site / rel
    if not target.exists():
        return False, f"missing target: {target}"

    current_hash = sha256_path(target)
    patched_hash = meta["patched_sha256"]
    original_hash = meta["original_sha256"]

    if current_hash == patched_hash:
        return True, f"{rel} already patched"

    if not force and current_hash != original_hash:
        bak = Path(str(target) + '.bak')
        if bak.exists() and sha256_path(bak) == current_hash:
            pass
        else:
            return False, f"{rel} has unrecognized hash {current_hash}"

    payload = decode_payload(meta["payload_b85_zlib"])
    if sha256_bytes(payload) != patched_hash:
        return False, f"embedded payload hash mismatch for {rel}"

    if dry_run:
        return True, f"{rel} would be patched"

    bak = Path(str(target) + '.bak')
    if not bak.exists():
        bak.write_bytes(target.read_bytes())

    target.write_bytes(payload)
    final_hash = sha256_path(target)
    if final_hash != patched_hash:
        return False, f"{rel} write verification failed: {final_hash}"
    return True, f"{rel} patched"


def main() -> int:
    parser = argparse.ArgumentParser(description="Apply full swap-safe patch for oMLX 0.3.4")
    parser.add_argument("--dry-run", action="store_true")
    parser.add_argument("--force", action="store_true")
    parser.add_argument("--site-packages", default=None)
    parser.add_argument("--skip-validate", action="store_true")
    args = parser.parse_args()

    site = target_site(args.site_packages)
    print(f"Target site-packages: {site}")
    print(f"Dry run: {args.dry_run}")

    if not site.exists():
        print(f"Target site-packages not found: {site}")
        return 1

    ok = True
    for rel in ["engine_pool.py", "process_memory_enforcer.py", "admin/routes.py", "engine/batched.py"]:
        passed, message = apply_file(site, rel, dry_run=args.dry_run, force=args.force)
        print(("✓" if passed else "✗"), message)
        ok = ok and passed

    if not ok:
        return 1

    if args.dry_run or args.skip_validate:
        return 0

    print("Running structural validation...")
    return 0 if validate_site(site, PATCH_VERSION) else 1


if __name__ == "__main__":
    raise SystemExit(main())
